import java.io.*;
import java.util.*;

public class SecureCommandExecution {

    public static void main(String[] args) {
        try {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to execute: ");
            String userInput = br.readLine();

            // Sanitize user input by splitting it into parts
            List<String> commandParts = Arrays.asList(userInput.split("\\s+"));

            // Execute the sanitized command using ProcessBuilder
            ProcessBuilder processBuilder = new ProcessBuilder(commandParts);
            Process process = processBuilder.start();

            // Read and display the output of the command
            BufferedReader outputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = outputReader.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            System.out.println("Error executing command: " + e.getMessage());
        }
    }
}

